"use client";

import { useState, useEffect } from "react";
import { fetchNewsList } from "@/lib/api";
import type { NewsListResponse } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";

const categories = [
  { value: "all", label: "전체" },
  { value: "global", label: "글로벌" },
  { value: "domestic", label: "국내" },
  { value: "policy", label: "정책" },
];

export default function IssuesPage() {
  const [category, setCategory] = useState("all");
  const [data, setData] = useState<NewsListResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    fetchNewsList(category)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [category]);

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">글로벌 이슈</h1>

      {/* 카테고리 필터 */}
      <div className="flex gap-2">
        {categories.map((c) => (
          <button
            key={c.value}
            onClick={() => setCategory(c.value)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${
              category === c.value
                ? "bg-skyblue text-white"
                : "bg-white/5 text-gray-400 hover:text-white hover:bg-white/10"
            }`}
          >
            {c.label}
          </button>
        ))}
      </div>

      {loading && <LoadingSpinner />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <div className="space-y-3">
          {data.items.map((n) => (
            <Link
              key={n.id}
              href={`/issues/${n.id}`}
              className="block bg-white/5 border border-white/10 rounded-xl p-5 hover:bg-white/10 transition-colors"
            >
              <div className="flex items-start justify-between gap-3">
                <div>
                  <span className={`inline-block text-[10px] font-bold uppercase px-2 py-0.5 rounded-full mb-2 ${
                    n.category === "global" ? "bg-blue-500/20 text-blue-300" :
                    n.category === "domestic" ? "bg-green-500/20 text-green-300" :
                    "bg-purple-500/20 text-purple-300"
                  }`}>
                    {n.category}
                  </span>
                  <p className="font-medium text-lg">{n.title}</p>
                  <p className="text-xs text-gray-400 mt-2">
                    {n.source} &middot; {new Date(n.published_at).toLocaleDateString("ko-KR")}
                  </p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
